"use client";
import { useState } from "react";
import "../../css/common/header.css"

export default function Header() {

    const [isOpen, setIsOpen] = useState(false);

    const toggleMenu=()=>{
        setIsOpen(!isOpen);
    };

    const closeMenu=()=>{
        setIsOpen(false);
    };


    return (
        <>
        <div className="header">
            <img src='/img/home/logo.png' />
            <div className="nav">
                <div className="gnb">
                </div>
                {/* hamberger section */}
                {/* 통합검색 상세검색 식별검색  */}
                <button className="ham-btn" onClick={toggleMenu}>
                    ☰
                </button>
            </div>
        </div>
        {/* backgroundOverlay */}
        <div className={`drawer-overlay ${isOpen ? 'open' : ''}`}
            onClick={closeMenu}></div>
        {/* sliding menu pannel */}
        <div className={`drawer-menu ${isOpen ? 'open' : ''}`}>
            <button className="close-btn" onClick={closeMenu}>닫기</button>
            <ul>
                    <li onClick={closeMenu}>통합검색</li>
                    <li onClick={closeMenu}>상세검색</li>
                    <li onClick={closeMenu}>식별검색</li>
                    <li onClick={closeMenu}>게시판</li>
                    <li onClick={closeMenu}>건강정보</li>
                    <li onClick={closeMenu}>소개</li>
                </ul>
        </div>
        </>
    );
}